import { useEffect, useState } from "react";
import API from "../services/api";
import { useNavigate } from "react-router-dom";

import {
  Chart as ChartJS,
  ArcElement,
  Tooltip,
  Legend
} from "chart.js";

import { Pie } from "react-chartjs-2";

ChartJS.register(ArcElement, Tooltip, Legend);

function Dashboard() {
  const [data, setData] = useState(null);
  const [editingId, setEditingId] = useState(null);
  const [editForm, setEditForm] = useState({
    title: "",
    topic: "",
    difficulty: "",
    platform: "",
  });

  const navigate = useNavigate();

  // ✅ SINGLE useEffect (correct)
  useEffect(() => {
    const token = localStorage.getItem("token");

    if (!token) {
      navigate("/login");
      return;
    }

    const fetchData = async () => {
      try {
        const res = await API.get("/dashboard");
        setData(res.data);
      } catch (error) {
        console.log(error);
        alert("Error fetching dashboard");
      }
    };

    fetchData();
  }, []);

  if (!data) return <p>Loading...</p>;

  // charts
  const difficultyData = {
    labels: Object.keys(data.difficultyCount),
    datasets: [
      {
        data: Object.values(data.difficultyCount),
        backgroundColor: ["#22c55e", "#facc15", "#ef4444"],
      },
    ],
  };

  const topicData = {
    labels: Object.keys(data.topicCount),
    datasets: [
      {
        data: Object.values(data.topicCount),
        backgroundColor: ["#3b82f6", "#a855f7", "#f97316"],
      },
    ],
  };

  // delete
  const handleDelete = async (id) => {
    try {
      await API.delete(`/dsa/${id}`);

      setData((prev) => ({
        ...prev,
        recent: prev.recent.filter((p) => p._id !== id),
        total: prev.total - 1,
      }));
    } catch (error) {
      console.log(error);
      alert("Error deleting");
    }
  };

  // edit
  const handleEditClick = (problem) => {
    setEditingId(problem._id);
    setEditForm(problem);
  };

  const handleEditChange = (e) => {
    setEditForm({ ...editForm, [e.target.name]: e.target.value });
  };

  const handleUpdate = async () => {
    try {
      const res = await API.put(`/dsa/${editingId}`, editForm);

      setData((prev) => ({
        ...prev,
        recent: prev.recent.map((p) =>
          p._id === editingId ? res.data : p
        ),
      }));

      setEditingId(null);
    } catch (error) {
      console.log(error);
      alert("Error updating");
    }
  };

  return (
    <div style={{ maxWidth: "900px", margin: "auto", padding: "20px" }}>
      <h1 style={{ textAlign: "center" }}>Dashboard</h1>

      <div style={{ background: "#1e293b", color: "white", padding: "20px", borderRadius: "10px", textAlign: "center" }}>
        <h2>Total Problems</h2>
        <h1>{data.total}</h1>
      </div>

      <div style={{ display: "flex", gap: "20px", marginTop: "20px", flexWrap: "wrap" }}>
        <div style={{ width: "320px", height: "320px", background: "#0f172a", padding: "15px", borderRadius: "10px", color: "white" }}>
          <h3>Difficulty</h3>
          <Pie data={difficultyData} options={{ maintainAspectRatio: false }} />
        </div>

        <div style={{ width: "320px", height: "320px", background: "#0f172a", padding: "15px", borderRadius: "10px", color: "white" }}>
          <h3>Topics</h3>
          <Pie data={topicData} options={{ maintainAspectRatio: false }} />
        </div>
      </div>

      <div style={{ marginTop: "20px", background: "#1e293b", padding: "20px", borderRadius: "10px", color: "white" }}>
        <h3>Recent Problems</h3>

        {data.recent.map((p) => (
          <div key={p._id} style={{ display: "flex", justifyContent: "space-between", marginBottom: "10px" }}>
            {editingId === p._id ? (
              <>
                <input name="title" value={editForm.title} onChange={handleEditChange} />
                <button onClick={handleUpdate}>Save</button>
              </>
            ) : (
              <>
                <span>{p.title}</span>

                <div>
                  <button onClick={() => handleEditClick(p)}>Edit</button>
                  <button onClick={() => handleDelete(p._id)}>Delete</button>
                </div>
              </>
            )}
          </div>
        ))}
      </div>
    </div>
  );
}

export default Dashboard;

import { useState, useEffect } from "react";
import API from "../services/api";
import { useNavigate } from "react-router-dom";

function Login() {
  const [email, setEmail] = useState("");
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  // 🔒 redirect if already logged in
  useEffect(() => {
    API.get("/dsa") // try protected route
      .then(() => navigate("/"))
      .catch(() => {});
  }, []);

  const handleLogin = async () => {
    if (!email) {
      return alert("Enter email");
    }

    try {
      setLoading(true);

      await API.post("/auth/login", { email });

      navigate("/");
    } catch (error) {
      alert(error.response?.data?.message || "Login failed");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={page}>
      <div style={card}>
        <h1 style={title}>PrepTracker 🚀</h1>
        <p style={subtitle}>Login to continue</p>

        <input
          type="email"
          placeholder="Enter email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          style={input}
        />

        <button
          onClick={handleLogin}
          style={button}
          disabled={loading}
        >
          {loading ? "Logging in..." : "Login"}
        </button>
      </div>
    </div>
  );
}

// 🎨 STYLES

const page = {
  height: "100vh",
  display: "flex",
  justifyContent: "center",
  alignItems: "center",
  background: "linear-gradient(135deg, #0f172a, #1e293b)",
};

const card = {
  width: "360px",
  padding: "30px",
  background: "rgba(15, 23, 42, 0.7)",
  backdropFilter: "blur(15px)",
  borderRadius: "12px",
  textAlign: "center",
  color: "white",
  boxShadow: "0 20px 50px rgba(0,0,0,0.5)",
};

const title = {
  marginBottom: "10px",
};

const subtitle = {
  marginBottom: "20px",
  color: "#94a3b8",
};

const input = {
  width: "100%",
  padding: "12px",
  marginBottom: "15px",
  borderRadius: "6px",
  border: "1px solid #334155",
  background: "#020617",
  color: "white",
};

const button = {
  width: "100%",
  padding: "12px",
  background: "#3b82f6",
  border: "none",
  borderRadius: "6px",
  color: "white",
  cursor: "pointer",
};

export default Login;
